org.machanism.macha.core.commons.config.Configurator conf = null;
org.machanism.machai.ai.provider.Genai provider = org.machanism.machai.ai.manager.GenaiProviderManager.getProvider("OpenAI:gpt-4o-mini", conf);
provider.instructions("You are a helpful assistant.");
provider.prompt("Summarize this repository.");
java.lang.String answer = provider.perform();
org.machanism.machai.ai.manager.GenaiProviderManager.addUsage(provider.usage());

org.machanism.machai.ai.tools.FunctionToolsLoader loader = org.machanism.machai.ai.tools.FunctionToolsLoader.getInstance();
org.machanism.macha.core.commons.config.Configurator conf = null;
loader.setConfiguration(conf);
org.machanism.machai.ai.provider.Genai provider = org.machanism.machai.ai.manager.GenaiProviderManager.getProvider("Claude:claude-3-5-sonnet", conf);
loader.applyTools(provider);

org.machanism.macha.core.commons.config.Configurator conf = null;
org.machanism.machai.ai.provider.Genai provider = org.machanism.machai.ai.manager.GenaiProviderManager.getProvider("OpenAI:gpt-4o-mini", conf);
provider.instructions("Answer concisely.");
provider.prompt("Explain the purpose of provider abstraction in one paragraph.");
