org.machanism.macha.core.commons.config.Configurator conf = null;
org.machanism.machai.ai.provider.EmbeddingProvider embeddings = org.machanism.machai.ai.manager.GenaiProviderManager.getEmbeddingProvider("OpenAI:text-embedding-3-small", conf);
java.util.List<java.lang.Float> vector = embeddings.embedding("GenAI Client provider-neutral prompt execution");

org.machanism.machai.ai.tools.FunctionToolsLoader tools = org.machanism.machai.ai.tools.FunctionToolsLoader.getInstance();
org.machanism.macha.core.commons.config.Configurator conf = null;
tools.setConfiguration(conf);
org.machanism.machai.ai.provider.Genai provider = org.machanism.machai.ai.manager.GenaiProviderManager.getProvider("OpenAI:gpt-4o-mini", conf);
tools.applyTools(provider);
provider.prompt("Use available tools only when necessary.");
java.lang.String answer = provider.perform();

