org.machanism.machai.ai.manager.GenaiProviderManager.addUsage(provider.usage());
org.machanism.machai.ai.manager.GenaiProviderManager.logUsage();

org.machanism.macha.core.commons.config.Configurator conf = null;
org.machanism.machai.ai.provider.Genai provider = org.machanism.machai.ai.manager.GenaiProviderManager.getProvider("Claude:claude-3-5-sonnet", conf);
org.machanism.machai.ai.tools.FunctionToolsLoader tools = org.machanism.machai.ai.tools.FunctionToolsLoader.getInstance();
tools.setConfiguration(conf);
tools.applyTools(provider);
provider.instructions("Use host tools only when they are relevant.");
